#!/usr/bin/env node
// C8 (0.8.11) — assemble `src/types/generated.ts` from the per-type ts-rs
// bindings in `backend/bindings/`. `make typegen` runs `cargo test
// export_bindings` (ts-rs writes one file per type) then this script, which:
//   • strips each file's `// generated by ts-rs` header + `import type …` lines
//     (in one aggregate file, cross-type refs resolve by name, no imports),
//   • keeps ts-rs's native `export type X = …` verbatim (object types, string
//     unions, AND tagged unions `{…} | {…}` — converting the latter to an
//     interface would be malformed; `export type` + `import type` work for all),
//   • concatenates in a STABLE (name-sorted) order so the output is
//     deterministic — a CI job diffs the regenerated file to catch drift.
//
// Historically `generated.ts` was hand-maintained and drifted from the Rust
// models (86 missing types at the 2026-07 audit). This closes that gap.
import { readFileSync, writeFileSync, readdirSync, statSync } from 'node:fs';
import { join, basename, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const HERE = dirname(fileURLToPath(import.meta.url));
const BINDINGS = join(HERE, '..', '..', 'backend', 'bindings');
const OUT = join(HERE, '..', 'src', 'types', 'generated.ts');

function walk(dir) {
  const out = [];
  for (const name of readdirSync(dir)) {
    const p = join(dir, name);
    if (statSync(p).isDirectory()) out.push(...walk(p));
    else if (name.endsWith('.ts')) out.push(p);
  }
  return out;
}

const files = walk(BINDINGS);
// Sort by type name (basename) for deterministic output.
files.sort((a, b) => basename(a).localeCompare(basename(b)));

const seen = new Set();
const blocks = [];
for (const f of files) {
  let src = readFileSync(f, 'utf8');
  src = src
    .replace(/^\/\/ This file was generated by \[ts-rs\].*$/m, '')
    .replace(/^import type .*;\s*$/gm, '')
    .trim();
  if (!src) continue;
  const m = src.match(/export type (\w+) =/);
  const name = m ? m[1] : basename(f, '.ts');
  if (seen.has(name)) continue;
  seen.add(name);
  // Normalize ts-rs's `bigint` (Rust u64/i64/usize) → `number`. Kronn's such
  // values (token counts, durations-ms, byte sizes, sequence numbers) are all
  // well under 2^53, the whole frontend does `number` arithmetic on them, and
  // JSON.parse yields `number` anyway (not BigInt). Matches the convention the
  // hand-maintained file used before this generator existed.
  src = src.replace(/\bbigint\b/g, 'number');
  blocks.push(src);
}

const header = `// ╔═══════════════════════════════════════════════════════════════════════════╗
// ║  AUTO-GENERATED — do not edit manually.                                     ║
// ║  Source: ts-rs bindings in backend/bindings/ (\`#[derive(TS)]\` on Rust      ║
// ║  models). Assembled by frontend/scripts/assemble-generated-types.mjs.       ║
// ║  Regenerate: \`make typegen\`. CI fails if this file drifts from the models.  ║
// ╚═══════════════════════════════════════════════════════════════════════════╝
`;

writeFileSync(OUT, header + '\n' + blocks.join('\n\n') + '\n');
console.log(`assembled ${blocks.length} types → ${OUT}`);
